function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;
  let timer = null;
  let lastArgs = null;
  let hasPending = false;

  const clear = () => {
    timer = null;
    hasPending = false;
    lastArgs = null;
  };

  const invoke = (context, args) => {
    fn.apply(context, args);
    clear();
  };

  const debounced = function (...args) {
    lastArgs = args;
    const context = this;

    if (timer) {
      clearTimeout(timer);
    }

    if (leading && !hasPending) {
      hasPending = true;
      invoke(context, args);
      return;
    }

    timer = setTimeout(() => {
      if (trailing && lastArgs) {
        invoke(context, lastArgs);
      } else {
        clear();
      }
    }, delay);
  };

  debounced.cancel = () => {
    if (timer) clearTimeout(timer);
    clear();
  };

  debounced.flush = () => {
    if (timer && lastArgs) {
      clearTimeout(timer);
      invoke(this, lastArgs);
    }
  };

  return debounced;
}
```

**用法：**

```javascript
const handleSearch = debounce(
  (query) => fetchSearchResults(query),
  300
);

input.addEventListener('input', (e) => handleSearch(e.target.value));
```

**核心逻辑：**

- 每次调用重置定时器，只有最后一次等待期满后才执行 `fn`
- `leading: true` 让第一次调用立即触发，后续调用仍被防抖
- `trailing` 控制是否在等待期结束后执行最后一次调用，默认 `true`
- `cancel()` 取消待执行的调用，`flush()` 立即执行待处理的调用

**适用场景：** 搜索输入、窗口 resize、滚动事件、自动保存。

