// 定义一个联合类型，每个成员都有共同的 kind 字段
type Shape =
  | { kind: "circle"; radius: number }
  | { kind: "rectangle"; width: number; height: number }
  | { kind: "triangle"; base: number; height: number };

// TypeScript 会根据 kind 收窄类型
function area(shape: Shape): number {
  switch (shape.kind) {
    case "circle":
      // 这里 shape 自动收窄为 { kind: "circle"; radius: number }
      return Math.PI * shape.radius ** 2;
    case "rectangle":
      return shape.width * shape.height;
    case "triangle":
      return (shape.base * shape.height) / 2;
  }
}

// 使用
console.log(area({ kind: "circle", radius: 5 }));       // 78.54
console.log(area({ kind: "rectangle", width: 4, height: 6 })); // 24
```

**关键点：**

- `kind` 是字面量类型（`"circle"` / `"rectangle"` / `"triangle"`），作为鉴别字段。
- `switch` 配合 `case` 后，TypeScript 自动收窄类型，每个分支里都能安全访问对应的自有属性。
- 如果新增一个成员（比如 `| { kind: "square"; side: number }`），`switch` 没覆盖的话 TypeScript 会报错（配合 `exhaustive check`），这是 discriminated union 最大的价值——**增删分支时编译器帮你兜底**。

